        let baz_symbol = symbols.iter().find(|s| s.name.as_str() == "Baz");
        assert!(baz_symbol.is_some(), "Expected to find a symbol named 'Baz'");
        let baz_symbol = baz_symbol.unwrap();
        assert_eq!(baz_symbol.container_name.as_deref(), Some("Foo"), "Baz variant should have Foo as container");

        // Search for enum variant "VariantA"
        let query = Query::new("VariantA".to_owned());
        let symbols = world_symbols(&db, query);

        assert!(!symbols.is_empty(), "Expected to find VariantA in symbols");
        let variant_a = symbols.iter().find(|s| s.name.as_str() == "VariantA");
        assert!(variant_a.is_some(), "Expected to find a symbol named 'VariantA'");
        let variant_a = variant_a.unwrap();
        assert_eq!(variant_a.container_name.as_deref(), Some("Another"), "VariantA should have Another as container");

        // Search for enum variant "VariantB"
        let query = Query::new("VariantB".to_owned());
        let symbols = world_symbols(&db, query);

        assert!(!symbols.is_empty(), "Expected to find VariantB in symbols");
        let variant_b = symbols.iter().find(|s| s.name.as_str() == "VariantB");
        assert!(variant_b.is_some(), "Expected to find a symbol named 'VariantB'");
        let variant_b = variant_b.unwrap();
        assert_eq!(variant_b.container_name.as_deref(), Some("Another"), "VariantB should have Another as container");
    }
